// PostgREST no puede computar NOW()-30d en el filtro, asi que el cutoff
// se calcula aqui y se inyecta en el filterString del nodo Supabase.
const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
return [{ json: { cutoff } }];

// Preparar datos para log en Historial (Supabase snake_case)
const deleted = $input.all();
const count = deleted.length;

if (count === 0) {
  return [{ json: { cleanedUp: 0, timestamp: new Date().toISOString() } }];
}

// Generar descripción con lista de asuntos eliminados (max 5)
const asuntos = deleted.slice(0, 5).map(d => d.json.asunto || '(sin asunto)').join(', ');
const descripcion = count <= 5
  ? `Limpieza automática: ${count} emails eliminados permanentemente (${asuntos})`
  : `Limpieza automática: ${count} emails eliminados permanentemente (${asuntos}... y ${count - 5} más)`;

return [{ json: {
  cleanedUp: count,
  timestamp: new Date().toISOString(),
  descripcion: descripcion
} }];
